window.__QUIZ_PARTS.push(...[{"title":"Sistemas Digitales","script":"repaso_sistemas_digitales.py","questions":[{"id":"SD-01","num":1,"text":"¿Cuál es el equivalente hexadecimal del número binario siguiente: 1110112?","questionImages":[],"options":[{"letter":"A","text":"3B16","images":["data:image/png;base64,"]},{"letter":"B","text":"59","images":["data:image/png;base64,"]},{"letter":"C","text":"7B16","images":["data:image/png;base64,"]},{"letter":"D","text":"B316","images":["data:image/png;base64,"]}],"answer":"A","multi":false,"explanation":"El binario 111011 se agrupa como 0011 1011, que corresponde a 3B en hexadecimal.","explanationImages":[]},{"id":"SD-02","num":2,"text":"Indique cuál es el complemento a dos del siguiente número binario: 11011.1102.","questionImages":[],"options":[{"letter":"A","text":"00100.010","images":["data:image/png;base64,"]},{"letter":"B","text":"00100.101","images":["data:image/png;base64,"]},{"letter":"C","text":"00100.001","images":["data:image/png;base64,"]},{"letter":"D","text":"0100.010","images":["data:image/png;base64,"]}],"answer":"A","multi":false,"explanation":"La opción marcada en el cuestionario es 00100.010.","explanationImages":[]},{"id":"SD-03","num":3,"text":"Para diseñar un circuito sumador/restador de dos números de cuatro bits, ¿qué circuitos integrados utilizaría?","questionImages":[],"options":[{"letter":"A","text":"7483, 7486","images":["data:image/png;base64,"]},{"letter":"B","text":"7485, 7486","images":["data:image/png;base64,"]},{"letter":"C","text":"7483, 7485","images":["data:image/png;base64,"]},{"letter":"D","text":"7485, 7486","images":["data:image/png;base64,"]}],"answer":"A","multi":false,"explanation":"El 7483 se usa como sumador de 4 bits y el 7486 contiene compuertas XOR, útiles para implementar la resta mediante complemento a dos.","explanationImages":[]},{"id":"SD-04","num":4,"text":"El circuito integrado 74138 es:","questionImages":[],"options":[{"letter":"A","text":"Decodificador 3 a 8","images":["data:image/png;base64,"]},{"letter":"B","text":"Decodificador 4 a 16","images":["data:image/png;base64,"]},{"letter":"C","text":"Multiplexor 8 a 1","images":["data:image/png;base64,"]},{"letter":"D","text":"Multiplexor 4 a 1","images":["data:image/png;base64,"]}],"answer":"A","multi":false,"explanation":"El 74138 es un decodificador/demultiplexor de 3 entradas a 8 salidas.","explanationImages":[]},{"id":"SD-05","num":5,"text":"Si al número binario 1100111 le añadimos el bit de paridad par, el nuevo código formado sería:","questionImages":[],"options":[{"letter":"A","text":"11001111","images":["data:image/png;base64,"]},{"letter":"B","text":"11001110","images":["data:image/png;base64,"]},{"letter":"C","text":"01100111","images":["data:image/png;base64,"]},{"letter":"D","text":"11100111","images":["data:image/png;base64,"]}],"answer":"B","multi":false,"explanation":"En 1100111 hay cinco unos. Para paridad par se agrega 0 al final, manteniendo una cantidad par de unos según la opción marcada: 11001110.","explanationImages":[]},{"id":"SD-06","num":6,"text":"¿Qué es una compuerta lógica?","questionImages":[],"options":[{"letter":"A","text":"Circuito combinacional para realizar operaciones lógicas sobre una o más entradas binarias y produce una salida binaria","images":["data:image/png;base64,"]},{"letter":"B","text":"Circuito eléctrico para realizar operaciones sobre una o más entradas que produce una salida","images":["data:image/png;base64,"]},{"letter":"C","text":"Circuito integrado para realizar operaciones eléctricas sobre una o más entradas","images":["data:image/png;base64,"]},{"letter":"D","text":"Son los circuitos integrados 7400, 74138","images":["data:image/png;base64,"]}],"answer":"A","multi":false,"explanation":"Una compuerta lógica realiza operaciones lógicas sobre entradas binarias y entrega una salida binaria.","explanationImages":[]},{"id":"SD-07","num":7,"text":"¿Qué es el código Hamming?","questionImages":[],"options":[{"letter":"A","text":"Código de detección y corrección de errores, donde se añaden varios bits de paridad","images":["data:image/png;base64,"]},{"letter":"B","text":"Código de detección de información con bits de paridad","images":["data:image/png;base64,"]},{"letter":"C","text":"Código de detección y corrección de bits de paridad","images":["data:image/png;base64,"]},{"letter":"D","text":"Código de detección y corrección de bits","images":["data:image/png;base64,"]}],"answer":"A","multi":false,"explanation":"El código Hamming usa bits de paridad para detectar y corregir errores.","explanationImages":[]},{"id":"SD-08","num":8,"text":"¿Qué es una compuerta XOR?","questionImages":[],"options":[{"letter":"A","text":"Compuerta lógica digital que devuelve un resultado 1 solo cuando sus dos entradas son diferentes","images":["data:image/png;base64,"]},{"letter":"B","text":"Compuerta lógica digital que devuelve un resultado 1 solo cuando sus dos entradas son iguales","images":["data:image/png;base64,"]},{"letter":"C","text":"Compuerta lógica digital que devuelve un resultado 0 solo cuando sus dos entradas son diferentes","images":["data:image/png;base64,"]},{"letter":"D","text":"Es el circuito integrado 7485","images":["data:image/png;base64,"]}],"answer":"A","multi":false,"explanation":"La compuerta XOR entrega 1 cuando sus entradas son diferentes.","explanationImages":[]},{"id":"SD-09","num":9,"text":"¿Cómo se representa el número 47 en código BCD?","questionImages":[],"options":[{"letter":"A","text":"01000111","images":["data:image/png;base64,"]},{"letter":"B","text":"101111","images":["data:image/png;base64,"]},{"letter":"C","text":"100111","images":["data:image/png;base64,"]},{"letter":"D","text":"47","images":["data:image/png;base64,"]}],"answer":"A","multi":false,"explanation":"En BCD, el 4 se representa como 0100 y el 7 como 0111. Por tanto, 47 es 0100 0111.","explanationImages":[]},{"id":"SD-10","num":10,"text":"¿Qué es el álgebra de Boole?","questionImages":[],"options":[{"letter":"A","text":"Rama de las matemáticas que trabaja con valores binarios (0 y 1) y operadores lógicos","images":["data:image/png;base64,"]},{"letter":"B","text":"Rama de las matemáticas para simplificar circuitos","images":["data:image/png;base64,"]},{"letter":"C","text":"Rama de las matemáticas digitales que trabaja con variables binarias","images":["data:image/png;base64,"]},{"letter":"D","text":"Rama de las matemáticas que trabaja con bits y operadores lógicos * . +","images":["data:image/png;base64,"]}],"answer":"A","multi":false,"explanation":"El álgebra de Boole trabaja con valores binarios y operadores lógicos, base del análisis y diseño de circuitos digitales.","explanationImages":[]}]},{"title":"Sistemas Digitales II","script":"repaso_sistemas_digitales_ii.py","questions":[{"id":"SD2-01","num":1,"text":"¿Cuál de las siguientes entidades en VHDL se utiliza para definir un decodificador de 1 a 2 con una entrada x y dos salidas y0 y y1 que corresponden a un vector y?","questionImages":[],"options":[{"letter":"A","text":"entity mux2to1 is port (A, B, S: in std_logic; Y: out std_logic); end entity; architecture Behavioral of mux2to1 is begin Y <= A and B; end Behavioral;","images":["data:image/png;base64,"]},{"letter":"B","text":"entity deco is port( x: in bit; y: out bit_vector(1 downto 0);","images":["data:image/png;base64,"]},{"letter":"C","text":"process(S) begin if S = '1' then Y <= A; else Y <= B; end if; end process;","images":["data:image/png;base64,"]}],"answer":"B","multi":false,"explanation":"La entidad correcta debe llamarse deco, tener la entrada x y la salida y como bit_vector(1 downto 0), porque se trata de un decodificador 1 a 2.","explanationImages":[]},{"id":"SD2-02","num":2,"text":"¿Cuál de las siguientes líneas estaría en el cuerpo de la arquitectura en VHDL que define una puerta OR de dos entradas?","questionImages":[],"options":[{"letter":"A","text":"Y <= A and B;","images":["data:image/png;base64,"]},{"letter":"B","text":"entidad deco is port( x: in bit; y: out bit_vector(1 downto 0) );","images":["data:image/png;base64,"]},{"letter":"C","text":"z <= x or y;","images":["data:image/png;base64,"]},{"letter":"D","text":"Y <= A xor B;","images":["data:image/png;base64,"]}],"answer":"C","multi":false,"explanation":"Una puerta OR de dos entradas se implementa con el operador or. Por eso la línea correcta es z <= x or y;","explanationImages":[]},{"id":"SD2-03","num":3,"text":"Se tiene un circuito que consta de un flip-flop D con su entrada D conectada a la salida q negada. ¿Cuál será la forma de onda de Q?","questionImages":[],"options":[{"letter":"A","text":"Triangular","images":["data:image/png;base64,"]},{"letter":"B","text":"El primer flip-flop estará en estado 1 y el segundo en estado 0","images":["data:image/png;base64,"]},{"letter":"C","text":"Media onda rectificada","images":["data:image/png;base64,"]},{"letter":"D","text":"Cuadrada","images":["data:image/png;base64,"]}],"answer":"D","multi":false,"explanation":"Si D se conecta a la salida negada, el flip-flop cambia de estado en cada pulso de reloj. Ese comportamiento genera una forma de onda cuadrada.","explanationImages":[]},{"id":"SD2-04","num":4,"text":"Se tiene un circuito que consta de un flip-flop D con su entrada D conectada a la salida Q. ¿Cuál será el valor de Q?","questionImages":[],"options":[{"letter":"A","text":"Cuadrada","images":["data:image/png;base64,"]},{"letter":"B","text":"El primer flip-flop estará en estado 1 y el segundo en estado 0","images":["data:image/png;base64,"]},{"letter":"C","text":"Media onda rectificada","images":["data:image/png;base64,"]},{"letter":"D","text":"Q no cambia","images":["data:image/png;base64,"]}],"answer":"D","multi":false,"explanation":"Si la entrada D se realimenta directamente desde Q, el flip-flop mantiene su estado. Por eso Q no cambia.","explanationImages":[]},{"id":"SD2-05","num":5,"text":"¿De qué señales dependen las salidas al mundo exterior de una máquina Moore?","questionImages":[],"options":[{"letter":"A","text":"Las entradas y el decodificador de siguiente estado","images":["data:image/png;base64,"]},{"letter":"B","text":"Las entradas del mundo exterior y el estado en el que está la máquina","images":["data:image/png;base64,"]},{"letter":"C","text":"Solo del estado en el que está la máquina","images":["data:image/png;base64,"]},{"letter":"D","text":"Del reloj y las entradas que cambien en un ciclo del reloj","images":["data:image/png;base64,"]}],"answer":"C","multi":false,"explanation":"En una máquina de Moore, las salidas dependen únicamente del estado actual de la máquina, no directamente de las entradas.","explanationImages":[]},{"id":"SD2-06","num":6,"text":"¿Qué se debe hacer en un diagrama ASM si en un mismo estado se tiene que preguntar por 2 entradas asincrónicas?","questionImages":[],"options":[{"letter":"A","text":"Eliminar un interruptor","images":["data:image/png;base64,"]},{"letter":"B","text":"Modificar la frecuencia del CLK para que acepte más de 2 entradas asincrónicas","images":["data:image/png;base64,"]},{"letter":"C","text":"Hay que tener un estado para cada entrada","images":["data:image/png;base64,"]},{"letter":"D","text":"Limitar siempre la pregunta a 3 entradas","images":["data:image/png;base64,"]}],"answer":"C","multi":false,"explanation":"En el diagrama ASM, si se deben evaluar entradas asincrónicas, se organiza el diseño usando un estado para cada entrada.","explanationImages":[]},{"id":"SD2-07","num":7,"text":"¿Cómo se identifica una entrada asincrónica en un diagrama ASM?","questionImages":[],"options":[{"letter":"A","text":"No es necesario identificarla","images":["data:image/png;base64,"]},{"letter":"B","text":"Hay que tener un estado para cada entrada","images":["data:image/png;base64,"]},{"letter":"C","text":"Un asterisco en el símbolo de diamante del ASM","images":["data:image/png;base64,"]},{"letter":"D","text":"Un asterisco en cualquier lugar del ASM","images":["data:image/png;base64,"]}],"answer":"C","multi":false,"explanation":"Una entrada asincrónica se identifica con un asterisco en el símbolo de diamante del ASM.","explanationImages":[]},{"id":"SD2-08","num":8,"text":"Si dentro de un process se asigna a una variable el valor de 1, ¿qué valor toma inmediatamente la variable?","questionImages":[],"options":[{"letter":"A","text":"La primera asignación que se le hizo","images":["data:image/png;base64,"]},{"letter":"B","text":"La primera y segunda asignaciones","images":["data:image/png;base64,"]},{"letter":"C","text":"Todas las asignaciones","images":["data:image/png;base64,"]},{"letter":"D","text":"1","images":["data:image/png;base64,"]}],"answer":"D","multi":false,"explanation":"En VHDL, una variable dentro de un process toma inmediatamente el valor asignado. Por eso toma el valor 1.","explanationImages":[]},{"id":"SD2-09","num":9,"text":"Si dentro de un process se asigna a una señal el valor de 1, ¿qué valor toma inmediatamente la señal antes de terminar el process?","questionImages":[],"options":[{"letter":"A","text":"El valor que tenía antes de realizar la asignación","images":["data:image/png;base64,"]},{"letter":"B","text":"La primera y segunda asignaciones","images":["data:image/png;base64,"]},{"letter":"C","text":"Todas las asignaciones","images":["data:image/png;base64,"]},{"letter":"D","text":"1","images":["data:image/png;base64,"]}],"answer":"A","multi":false,"explanation":"En VHDL, una señal no se actualiza inmediatamente dentro del process; conserva el valor anterior hasta finalizar el proceso de actualización.","explanationImages":[]},{"id":"SD2-10","num":10,"text":"En un diagrama ASM, ¿qué sentencias se podrían utilizar para implementarlo?","questionImages":[],"options":[{"letter":"A","text":"Solo los when else","images":["data:image/png;base64,"]},{"letter":"B","text":"Solo if","images":["data:image/png;base64,"]},{"letter":"C","text":"Solo case","images":["data:image/png;base64,"]},{"letter":"D","text":"Case e if","images":["data:image/png;base64,"]}],"answer":"D","multi":false,"explanation":"Un diagrama ASM se puede implementar usando estructuras case e if, según el estado y las condiciones de decisión.","explanationImages":[]}]},{"title":"Software para ingeniería","script":"repaso_software_para_ingenieria.py","questions":[{"id":"SW-01","num":1,"text":"Un ingeniero en Telecomunicaciones precisa simular interferencia compleja en un canal usando una señal de ruido blanco complejo. ¿Cuál de los siguientes comandos en MATLAB genera correctamente un vector de 1x1000 muestras de ruido complejo aleatorio con media cero y varianza unitaria?","questionImages":[],"options":[{"letter":"A","text":"z = rand(1,1000) + 1i*rand(1,1000);","images":["data:image/png;base64,"]},{"letter":"B","text":"z = rand(1,1000) + 1i*rand(1,1000);","images":["data:image/png;base64,"]},{"letter":"C","text":"z = complex(randn(1,1000));","images":["data:image/png;base64,"]},{"letter":"D","text":"z = 1i*randn(1,1000);","images":["data:image/png;base64,"]}],"answer":"A","multi":false,"explanation":"La opción correcta usa randn para generar componentes gaussianas de media cero, una real y otra imaginaria, formando ruido complejo aleatorio.","explanationImages":[]},{"id":"SW-02","num":2,"text":"En una simulación de atenuación de señal, se requiere definir una función exponencial decreciente sin crear un archivo de función. ¿Cuál opción representa correctamente una función anónima en MATLAB que modele esta atenuación en el tiempo?","questionImages":[],"options":[{"letter":"A","text":"exp_decay = @(t) exp(t);","images":["data:image/png;base64,"]},{"letter":"B","text":"exp_decay = @(t) exp(-t);","images":["data:image/png;base64,"]},{"letter":"C","text":"exp_decay(t) = exp(-t);","images":["data:image/png;base64,"]},{"letter":"D","text":"function exp_decay(t) = exp(-t);","images":["data:image/png;base64,"]}],"answer":"B","multi":false,"explanation":"En MATLAB, una función anónima se define con @(variable). Como la atenuación es decreciente, se usa exp(-t).","explanationImages":[]},{"id":"SW-03","num":3,"text":"¿Qué comando MATLAB genera correctamente una señal AM con una portadora de 10 kHz y una señal moduladora de 1 kHz para representar una señal senoidal modulada en amplitud?","questionImages":[],"options":[{"letter":"A","text":"t = 0:1e-6:1; x = sin(2*pi*10000*t).*cos(2*pi*1000*t);","images":["data:image/png;base64,"]},{"letter":"B","text":"t = 0:1e-6:1; x = sin(2*pi*1000*t + 2*pi*10000*t);","images":["data:image/png;base64,"]},{"letter":"C","text":"t = 0:1e-6:1; x = sin(2*pi*1000*t).*cos(2*pi*10000*t);","images":["data:image/png;base64,"]},{"letter":"D","text":"t = 0:1e-6:1; x = cos(2*pi*1000*t).*cos(2*pi*10000*t);","images":["data:image/png;base64,"]}],"answer":"C","multi":false,"explanation":"La opción resaltada en el PDF multiplica la señal moduladora de 1 kHz por la portadora de 10 kHz, representando la modulación en amplitud.","explanationImages":[]},{"id":"SW-04","num":4,"text":"Encontrar en MATLAB la Transformada Rápida de Fourier y el espectro de frecuencias de la señal: x(t) = 0.2sen(2πt) + 0.4cos(4πt).","questionImages":[],"options":[{"letter":"A","text":"t = 0:0.001:1; x = 0.2*sin(2*pi*t) + 0.4*cos(4*pi*t); X = fft(x); f = (0:length(X)-1)/length(t); plot(f, abs(X));","images":["data:image/png;base64,"]},{"letter":"B","text":"t = 0:0.001:1; x = 0.2*sin(2*pi*t) + 0.4*cos(4*pi*t); X = fft(x); f = (0:length(X)-1); plot(f, abs(X));","images":["data:image/png;base64,"]},{"letter":"C","text":"t = 0:0.001:1; x = 0.2*sin(2*pi*t) + 0.4*cos(4*pi*t); X = fft(x); f = (0:length(X)-1)/length(X); plot(f, abs(X));","images":["data:image/png;base64,"]},{"letter":"D","text":"t = 0:0.001:1; x = 0.2*sin(2*pi*t) + 0.4*cos(4*pi*t); X = fft(x); f = (0:length(X)-1)/(length(t)*0.001); plot(f, abs(X));","images":["data:image/png;base64,"]}],"answer":"D","multi":false,"explanation":"Para obtener el eje de frecuencias en Hz se considera el período de muestreo Ts = 0.001, por eso se usa f = (0:N-1)/(N*Ts).","explanationImages":[]},{"id":"SW-05","num":5,"text":"En un sistema de adquisición de señales, se conecta un control tipo Knob en el panel frontal de LabVIEW a una estructura Case en el diagrama de bloques. ¿Qué tipo de control es y qué función desempeña?","questionImages":[],"options":[{"letter":"A","text":"Es un control numérico para modificar parámetros en tiempo de ejecución","images":["data:image/png;base64,"]},{"letter":"B","text":"Es un indicador que muestra valores analógicos","images":["data:image/png;base64,"]},{"letter":"C","text":"Es un control de cadena de texto","images":["data:image/png;base64,"]},{"letter":"D","text":"Es un interruptor binario para activar funciones","images":["data:image/png;base64,"]}],"answer":"A","multi":false,"explanation":"Un Knob en LabVIEW es un control numérico que permite cambiar parámetros mientras el VI se ejecuta.","explanationImages":[]},{"id":"SW-06","num":6,"text":"Un sistema implementado en LabVIEW controla la transmisión de datos en paquetes a través de un canal simulado. Cada paquete debe contener un ID, datos y un chequeo de paridad. ¿Cómo debe diseñarse el sistema utilizando estructuras gráficas en el diagrama de bloques?","questionImages":[],"options":[{"letter":"A","text":"Crear un Event Structure con nodos numéricos concatenados y lógica de XOR","images":["data:image/png;base64,"]},{"letter":"B","text":"Usar un While Loop con shift registers para generar ID, un String array para datos, y un SubVI para calcular paridad","images":["data:image/png;base64,"]},{"letter":"C","text":"Utilizar un Flat Sequence que concatene todos los datos y aplique una función seno como verificación","images":["data:image/png;base64,"]},{"letter":"D","text":"Usar nodos DAQ y generar la paridad directamente desde el Front Panel con un botón de control","images":["data:image/png;base64,"]}],"answer":"B","multi":false,"explanation":"La opción correcta organiza el proceso con While Loop, shift registers para conservar/actualizar el ID, arreglo de datos y un SubVI para el cálculo de paridad.","explanationImages":[]},{"id":"SW-07","num":7,"text":"¿Qué tipo de dato se usa para activar la alarma y cuál función lógica es adecuada para un técnico que diseña un VI que enciende una alarma si la temperatura supera los 70 °C?","questionImages":[],"options":[{"letter":"A","text":"Tipo String con función Comparar Texto","images":["data:image/png;base64,"]},{"letter":"B","text":"Tipo Numeric con función Suma","images":["data:image/png;base64,"]},{"letter":"C","text":"Tipo Boolean con función Mayor que","images":["data:image/png;base64,"]},{"letter":"D","text":"Tipo Boolean con función Concatenar","images":["data:image/png;base64,"]}],"answer":"C","multi":false,"explanation":"La condición de alarma se evalúa con una comparación Mayor que; el resultado de esa comparación es Boolean y sirve para activar la alarma.","explanationImages":[]},{"id":"SW-08","num":8,"text":"Se solicita implementar en LabVIEW una estructura de control que modifique dinámicamente el número de iteraciones de un For Loop en función del valor de entrada de una señal externa, por ejemplo, el número de paquetes recibidos. ¿Qué técnica o estructura se debe emplear para permitir este comportamiento?","questionImages":[],"options":[{"letter":"A","text":"Utilizar shift registers con un valor constante de iteración","images":["data:image/png;base64,"]},{"letter":"B","text":"Encapsular el For Loop en una estructura Case según el número de paquetes","images":["data:image/png;base64,"]},{"letter":"C","text":"Colocar el For Loop dentro de un While Loop con condición de parada","images":["data:image/png;base64,"]},{"letter":"D","text":"Crear un For Loop con terminal de iteración conectado dinámicamente a una entrada externa validada","images":["data:image/png;base64,"]}],"answer":"D","multi":false,"explanation":"El número de iteraciones del For Loop debe conectarse dinámicamente a una entrada externa validada para que cambie según la señal o cantidad de paquetes.","explanationImages":[]},{"id":"SW-09","num":9,"text":"Se diseña una planta de distribución de fibra óptica en AutoCAD, utilizando layouts a escala para documentación técnica. Desea representar diferentes niveles de detalle en distintos viewports de una misma hoja. ¿Cuál es la secuencia correcta de acciones para conseguirlo?","questionImages":[],"options":[{"letter":"A","text":"Definir múltiples viewports en Paper Space, asignar escalas individuales y congelar capas según necesidad","images":["data:image/png;base64,"]},{"letter":"B","text":"Activar múltiples viewports en Model Space y ajustar el zoom","images":["data:image/png;base64,"]},{"letter":"C","text":"Crear múltiples layouts y usar el comando REGION para cada uno","images":["data:image/png;base64,"]},{"letter":"D","text":"Insertar bloques dinámicos y modificar sus propiedades desde el tab Annotate","images":["data:image/png;base64,"]}],"answer":"A","multi":false,"explanation":"Para diferentes niveles de detalle en una misma hoja se usan viewports en Paper Space, cada uno con su escala y configuración de capas.","explanationImages":[]},{"id":"SW-10","num":10,"text":"Durante la elaboración del plano de una red de canalización subterránea para fibra óptica, se requiere trazar una línea central o eje que mantenga equidistancia entre dos ductos curvos. ¿Qué comando permite generar correctamente esta línea, manteniendo precisión geométrica?","questionImages":[],"options":[{"letter":"A","text":"COPY con coordenadas absolutas","images":["data:image/png;base64,"]},{"letter":"B","text":"OFSET desde una polilínea, calculando la mitad de la distancia","images":["data:image/png;base64,"]},{"letter":"C","text":"SPLINE entre puntos de control","images":["data:image/png;base64,"]},{"letter":"D","text":"TRIM seguido de FILET para ajustar vértices","images":["data:image/png;base64,"]}],"answer":"B","multi":false,"explanation":"OFSET permite generar una línea paralela o equidistante respecto a una polilínea, manteniendo precisión geométrica.","explanationImages":[]}]},{"title":"Sostenibilidad Ambiental","script":"repaso_sostenibilidad_ambiental.py","questions":[{"id":"SA-01","num":1,"text":"¿Cuál de los siguientes pilares de los Objetivos de Desarrollo Sostenible (ODS) se enfoca en garantizar que las economías sean inclusivas y sostenibles, promoviendo el crecimiento económico sin dejar a nadie atrás?","questionImages":[],"options":[{"letter":"A","text":"Prosperidad","images":["data:image/png;base64,"]},{"letter":"B","text":"Personas","images":["data:image/png;base64,"]},{"letter":"C","text":"Planeta","images":["data:image/png;base64,"]},{"letter":"D","text":"Paz","images":["data:image/png;base64,"]}],"answer":"A","multi":false,"explanation":"El pilar Prosperidad busca que las economías sean inclusivas y sostenibles, promoviendo el crecimiento económico sin dejar a nadie atrás.","explanationImages":[]},{"id":"SA-02","num":2,"text":"¿Cuál de las siguientes afirmaciones describe correctamente uno de los principales mecanismos de mercado introducidos por el Protocolo de Kioto para reducir las emisiones de gases de efecto invernadero entre los países industrializados?","questionImages":[],"options":[{"letter":"A","text":"El Mecanismo de Desarrollo Limpio permite a los países en desarrollo vender sus derechos de emisión a los países industrializados.","images":["data:image/png;base64,"]},{"letter":"B","text":"El Comercio de emisiones permite a los países desarrollados comprar y vender derechos de emisión para cumplir con sus objetivos de reducción de emisiones.","images":["data:image/png;base64,"]},{"letter":"C","text":"El Programa de monitoreo y verificación establece un sistema obligatorio para la medición de emisiones de gases en países no firmantes del Protocolo.","images":["data:image/png;base64,"]},{"letter":"D","text":"La Iniciativa de adaptación permite a los países en desarrollo financiar proyectos de adaptación sin restricciones en el uso de créditos de carbono.","images":["data:image/png;base64,"]}],"answer":"B","multi":false,"explanation":"El comercio de emisiones permite que los países desarrollados compren y vendan derechos de emisión para cumplir sus metas de reducción.","explanationImages":[]},{"id":"SA-03","num":3,"text":"¿Cuál de los siguientes factores NO está incluido como uno de los límites planetarios establecidos por el estudio de “Los límites del planeta para la humanidad” de 2009?","questionImages":[],"options":[{"letter":"A","text":"Cambio climático","images":["data:image/png;base64,"]},{"letter":"B","text":"Acidificación de los océanos","images":["data:image/png;base64,"]},{"letter":"C","text":"Uso del agua dulce","images":["data:image/png;base64,"]},{"letter":"D","text":"Crecimiento de la población mundial","images":["data:image/png;base64,"]}],"answer":"D","multi":false,"explanation":"El crecimiento de la población mundial no aparece como uno de los límites planetarios definidos en el estudio de 2009.","explanationImages":[]},{"id":"SA-04","num":4,"text":"¿Cuál de los siguientes servicios ecosistémicos desempeñados por el suelo tiene un impacto directo en la purificación del agua y el tratamiento de residuos?","questionImages":[],"options":[{"letter":"A","text":"Servicios de regulación","images":["data:image/png;base64,"]},{"letter":"B","text":"Servicios de soporte","images":["data:image/png;base64,"]},{"letter":"C","text":"Servicios culturales","images":["data:image/png;base64,"]},{"letter":"D","text":"Servicios de provisionamiento","images":["data:image/png;base64,"]}],"answer":"A","multi":false,"explanation":"La purificación del agua y el tratamiento de residuos forman parte de los servicios de regulación que puede brindar el suelo.","explanationImages":[]},{"id":"SA-05","num":5,"text":"¿Cuál de los siguientes contaminantes atmosféricos secundarios se forma principalmente a través de la reacción química entre los óxidos de nitrógeno (NOx) y los compuestos orgánicos volátiles (COVs) en presencia de la luz solar?","questionImages":[],"options":[{"letter":"A","text":"Ozono troposférico (O3)","images":["data:image/png;base64,"]},{"letter":"B","text":"Dióxido de azufre (SO2)","images":["data:image/png;base64,"]},{"letter":"C","text":"Monóxido de carbono (CO)","images":["data:image/png;base64,"]},{"letter":"D","text":"Material particulado (PM)","images":["data:image/png;base64,"]}],"answer":"A","multi":false,"explanation":"El ozono troposférico se forma por reacciones fotoquímicas entre NOx y COVs en presencia de luz solar.","explanationImages":[]},{"id":"SA-06","num":6,"text":"¿Cuál de las siguientes afirmaciones describe correctamente una característica distintiva de la contaminación difusa en comparación con la puntual?","questionImages":[],"options":[{"letter":"A","text":"La contaminación difusa proviene de fuentes específicas y localizadas, como las chimeneas de las fábricas.","images":["data:image/png;base64,"]},{"letter":"B","text":"La contaminación puntual se distribuye de manera uniforme sobre grandes áreas y es difícil de rastrear.","images":["data:image/png;base64,"]},{"letter":"C","text":"La contaminación difusa se origina en múltiples fuentes dispersas, como el escurrimiento de productos químicos desde extensas áreas agrícolas o urbanas.","images":["data:image/png;base64,"]},{"letter":"D","text":"La contaminación puntual es más fácil de controlar porque se concentra en áreas amplias y menos identificables.","images":["data:image/png;base64,"]}],"answer":"C","multi":false,"explanation":"La contaminación difusa se caracteriza por provenir de múltiples fuentes dispersas, lo que dificulta su rastreo y control.","explanationImages":[]},{"id":"SA-07","num":7,"text":"¿Cuál de las siguientes estrategias de gestión de desechos sólidos busca minimizar la cantidad de residuos generados en su origen y es considerada la más efectiva en términos de sostenibilidad ambiental?","questionImages":[],"options":[{"letter":"A","text":"Reciclaje y reutilización de materiales","images":["data:image/png;base64,"]},{"letter":"B","text":"Incineración controlada de desechos","images":["data:image/png;base64,"]},{"letter":"C","text":"Reducción en la fuente","images":["data:image/png;base64,"]},{"letter":"D","text":"Disposición en vertederos controlados","images":["data:image/png;base64,"]}],"answer":"C","multi":false,"explanation":"La reducción en la fuente es la estrategia más efectiva porque evita o minimiza la generación de residuos desde el origen.","explanationImages":[]},{"id":"SA-08","num":8,"text":"¿A qué hace referencia el potencial de calentamiento global (PCG) de un gas de efecto invernadero?","questionImages":[],"options":[{"letter":"A","text":"La capacidad de un gas para reflejar la radiación solar y reducir el calentamiento terrestre.","images":["data:image/png;base64,"]},{"letter":"B","text":"La cantidad de energía que un gas puede absorber antes de descomponerse en la atmósfera.","images":["data:image/png;base64,"]},{"letter":"C","text":"La cantidad de radiación infrarroja que un gas puede absorber y emitir, comparado con el dióxido de carbono (CO2) durante un período determinado.","images":["data:image/png;base64,"]},{"letter":"D","text":"La rapidez con la que un gas de efecto invernadero se disuelve en el agua de los océanos.","images":["data:image/png;base64,"]}],"answer":"C","multi":false,"explanation":"El PCG compara la capacidad de un gas para absorber y emitir radiación infrarroja frente al CO2 durante un período específico.","explanationImages":[]},{"id":"SA-09","num":9,"text":"¿Cuál de los siguientes factores tiene un impacto significativo en la huella de carbono de los productos electrónicos, especialmente en dispositivos como teléfonos móviles y computadoras portátiles?","questionImages":[],"options":[{"letter":"A","text":"La cantidad de energía utilizada durante la fase de uso del dispositivo.","images":["data:image/png;base64,"]},{"letter":"B","text":"La energía empleada en el proceso de reciclaje de dispositivos al final de su vida útil.","images":["data:image/png;base64,"]},{"letter":"C","text":"Las emisiones asociadas con la extracción y procesamiento de minerales como el litio y el cobalto utilizados en las baterías.","images":["data:image/png;base64,"]},{"letter":"D","text":"El empaquetado y transporte del producto al consumidor final.","images":["data:image/png;base64,"]}],"answer":"C","multi":false,"explanation":"En dispositivos electrónicos, la extracción y procesamiento de minerales como litio y cobalto puede aportar de forma importante a la huella de carbono.","explanationImages":[]},{"id":"SA-10","num":10,"text":"¿Qué significa el acrónimo CRETIB en el contexto de la clasificación de residuos peligrosos, y por qué estos materiales requieren un manejo especial?","questionImages":[],"options":[{"letter":"A","text":"CRETIB hace referencia a residuos que son principalmente inofensivos para el medio ambiente y la salud humana, ya que se consideran biodegradables.","images":["data:image/png;base64,"]},{"letter":"B","text":"CRETIB es un acrónimo que describe residuos con propiedades corrosivas, reactivas, explosivas, tóxicas, infecciosas y biológicas, los cuales son peligrosos y requieren un manejo y disposición especial para evitar daños a la salud y al medio ambiente.","images":["data:image/png;base64,"]},{"letter":"C","text":"CRETIB es una clasificación de residuos que se refiere a los materiales reciclables de bajo impacto ambiental, como papel y vidrio.","images":["data:image/png;base64,"]},{"letter":"D","text":"CRETIB describe residuos sólidos orgánicos que son fáciles de tratar y compostar sin ningún riesgo de contaminación.","images":["data:image/png;base64,"]}],"answer":"B","multi":false,"explanation":"CRETIB identifica residuos con características corrosivas, reactivas, explosivas, tóxicas, infecciosas y biológicas; por eso requieren manejo especial.","explanationImages":[]}]},{"title":"Televisión Digital","script":"repaso_television_digital.py","questions":[{"id":"TV-01","num":1,"text":"¿Cuáles son los modos de operación de DVB-T?","questionImages":[],"options":[{"letter":"A","text":"Modo FFT 2K","images":["data:image/png;base64,"]},{"letter":"B","text":"Modo FFT 4K","images":["data:image/png;base64,"]},{"letter":"C","text":"Modo FFT 6 K","images":["data:image/png;base64,"]},{"letter":"D","text":"Modo FFT 16K","images":["data:image/png;base64,"]}],"answer":"B","multi":false,"explanation":"Según la clave del cuestionario, el modo de operación señalado para DVB-T es Modo FFT 4K.","explanationImages":[]},{"id":"TV-02","num":2,"text":"¿Qué sucede al incrementar el modo de operación de un sistema DVB-T2?","questionImages":[],"options":[{"letter":"A","text":"Genera caída abrupta fuera de banda","images":["data:image/png;base64,"]},{"letter":"B","text":"Genera caída abrupta dentro de banda","images":["data:image/png;base64,"]},{"letter":"C","text":"Genera tiempos de símbolo más cortos","images":["data:image/png;base64,"]},{"letter":"D","text":"Genera una menor resolución en frecuencia","images":["data:image/png;base64,"]}],"answer":"D","multi":false,"explanation":"La opción resaltada en el cuestionario indica que al incrementar el modo de operación se genera una menor resolución en frecuencia.","explanationImages":[]},{"id":"TV-03","num":3,"text":"¿Cuál es el proceso para la sintonización de un canal para ISDB-T con el equipo PROMAX?","questionImages":[],"options":[{"letter":"A","text":"Pulsación de S, T; Pulsación corta de A, D; Pulsación botón ingresar la frecuencia; Mostrar video en pantalla","images":["data:image/png;base64,"]},{"letter":"B","text":"Pulsación de S, T; Pulsación larga de A, D; Pulsación botón ingresar el tiempo; Mostrar video en pantalla","images":["data:image/png;base64,"]},{"letter":"C","text":"Pulsación de S, T; Pulsación corta de A, D; Pulsación botón ingresar el tiempo; Mostrar video en pantalla","images":["data:image/png;base64,"]},{"letter":"D","text":"Pulsación de S, T; Pulsación larga de A, D; Pulsación botón ingresar la frecuencia; Mostrar video en pantalla","images":["data:image/png;base64,"]}],"answer":"A","multi":false,"explanation":"El proceso correcto combina la pulsación de S y T, pulsación corta de A y D, ingreso de la frecuencia y visualización del video en pantalla.","explanationImages":[]},{"id":"TV-04","num":4,"text":"¿Cuáles son las características principales de una señal ISDB-Tb?","questionImages":[],"options":[{"letter":"A","text":"Modulación OFDM","images":["data:image/png;base64,"]},{"letter":"B","text":"Modos de operación 2k, 4k, 6k, 8k","images":["data:image/png;base64,"]},{"letter":"C","text":"Pensada para canales de 5 MHz","images":["data:image/png;base64,"]},{"letter":"D","text":"Utiliza portadoras piloto para estimación del canal","images":["data:image/png;base64,"]}],"answer":["A","D"],"multi":true,"explanation":"El cuestionario marca dos características principales: modulación OFDM y uso de portadoras piloto para estimación del canal.","explanationImages":[]},{"id":"TV-05","num":5,"text":"El uso de FFT más altas, por ejemplo 8K, permite:","questionImages":[],"options":[{"letter":"A","text":"Eliminar la propagación multicamino","images":["data:image/png;base64,"]},{"letter":"B","text":"Mejorar la recepción fija","images":["data:image/png;base64,"]},{"letter":"C","text":"Mejora la recepción en interiores","images":["data:image/png;base64,"]},{"letter":"D","text":"Ninguna de las anteriores","images":["data:image/png;base64,"]},{"letter":"E","text":"Todas las anteriores","images":["data:image/png;base64,"]}],"answer":"B","multi":false,"explanation":"La opción resaltada indica que el uso de FFT más altas, como 8K, permite mejorar la recepción fija.","explanationImages":[]},{"id":"TV-06","num":6,"text":"El entrelazado temporal es útil para:","questionImages":[],"options":[{"letter":"A","text":"Dar mayor separación entre las portadoras OFDM","images":["data:image/png;base64,"]},{"letter":"B","text":"Afrontar los desvanecimientos controlados del canal","images":["data:image/png;base64,"]},{"letter":"C","text":"Recepción móvil (indoor outdoor)","images":["data:image/png;base64,"]},{"letter":"D","text":"Ninguna es correcta","images":["data:image/png;base64,"]}],"answer":"B","multi":false,"explanation":"El entrelazado temporal ayuda a afrontar los desvanecimientos del canal.","explanationImages":[]},{"id":"TV-07","num":7,"text":"El entrelazado frecuencial consiste en:","questionImages":[],"options":[{"letter":"A","text":"Cambiar las posiciones de las portadoras.","images":["data:image/png;base64,"]},{"letter":"B","text":"Distribuir los datos en varias portadoras no contiguas en frecuencia.","images":["data:image/png;base64,"]},{"letter":"C","text":"Utilizar menos portadoras que las definidas para el modo específico que se usa.","images":["data:image/png;base64,"]},{"letter":"D","text":"Todas las anteriores son correctas","images":["data:image/png;base64,"]}],"answer":"B","multi":false,"explanation":"El entrelazado frecuencial distribuye los datos en varias portadoras no contiguas en frecuencia.","explanationImages":[]},{"id":"TV-08","num":8,"text":"El estándar ISDB-Tb utiliza codificación de video:","questionImages":[],"options":[{"letter":"A","text":"MPEG-2","images":["data:image/png;base64,"]},{"letter":"B","text":"MPEG-5","images":["data:image/png;base64,"]},{"letter":"C","text":"MPEG-4","images":["data:image/png;base64,"]},{"letter":"D","text":"Ninguna de las anteriores","images":["data:image/png;base64,"]}],"answer":"C","multi":false,"explanation":"El estándar ISDB-Tb utiliza codificación de video MPEG-4.","explanationImages":[]},{"id":"TV-09","num":9,"text":"¿A qué se refieren las siglas IPTV?","questionImages":[],"options":[{"letter":"A","text":"IPTV un protocolo en sí mismo.","images":["data:image/png;base64,"]},{"letter":"B","text":"IPTV es una tecnología que permite transmisión de señales de video sobre protocolo IP.","images":["data:image/png;base64,"]},{"letter":"C","text":"IPTV es televisión sobre Internet.","images":["data:image/png;base64,"]},{"letter":"D","text":"IPTV es una tecnología que se despliega sobre redes propietarias de operadores que pretenden ofrecer servicios de televisión por subscripción distinta a los satelitales y CATV y algunos servicios innovadores e interactivos.","images":["data:image/png;base64,"]}],"answer":"B","multi":false,"explanation":"IPTV se refiere a una tecnología que permite la transmisión de señales de video sobre protocolo IP.","explanationImages":[]},{"id":"TV-10","num":10,"text":"¿Cuáles son los componentes de una solución IPTV a nivel de la capa de transporte?","questionImages":[],"options":[{"letter":"A","text":"Contiene encoders (MPEG-2, MPEG-4 o Windows Media), middleware, servidores de video en demanda.","images":["data:image/png;base64,"]},{"letter":"B","text":"Redes IP/MPLS con QoS, grandes anchos de banda (DWDM, Metroethernet).","images":["data:image/png;base64,"]},{"letter":"C","text":"ADSL, VDSL, PON (FTTx).","images":["data:image/png;base64,"]},{"letter":"D","text":"Set Top Box.","images":["data:image/png;base64,"]}],"answer":"B","multi":false,"explanation":"A nivel de la capa de transporte, la solución IPTV se apoya en redes IP/MPLS con QoS y grandes anchos de banda.","explanationImages":[]}]},{"title":"Trabajo de Integración Curricular","script":"repaso_trabajo_de_integracion_curricular.py","questions":[{"id":"TIC-01","num":1,"text":"Enumerar los elementos que deben ser tomados en cuenta para escribir un objetivo específico.","questionImages":[],"options":[{"letter":"A","text":"El cómo y para qué es lo más importante","images":["data:image/png;base64,"]},{"letter":"B","text":"Solo el verbo en infinitivo","images":["data:image/png;base64,"]},{"letter":"C","text":"Hay que redactar solo en forma que sea comprensible.","images":["data:image/png;base64,"]},{"letter":"D","text":"El verbo en infinitivo, el que, el cómo, el para qué.","images":["data:image/png;base64,"]}],"answer":"D","multi":false,"explanation":"Para redactar un objetivo específico se consideran el verbo en infinitivo, el qué, el cómo y el para qué.","explanationImages":[]},{"id":"TIC-02","num":2,"text":"Identificar qué es la bibliografía.","questionImages":[],"options":[{"letter":"A","text":"Una opinión con fundamento.","images":["data:image/png;base64,"]},{"letter":"B","text":"Un resultado comprobado","images":["data:image/png;base64,"]},{"letter":"C","text":"Una explicación probable y comprobable del fenómeno.","images":["data:image/png;base64,"]},{"letter":"D","text":"Ninguna de las anteriores.","images":["data:image/png;base64,"]}],"answer":"D","multi":false,"explanation":"La bibliografía corresponde a las fuentes consultadas, por eso ninguna de las opciones A, B o C define correctamente el concepto.","explanationImages":[]},{"id":"TIC-03","num":3,"text":"Identificar qué es la población.","questionImages":[],"options":[{"letter":"A","text":"Se enfoca en experiencias personales.","images":["data:image/png;base64,"]},{"letter":"B","text":"Usa entrevistas abiertas.","images":["data:image/png;base64,"]},{"letter":"C","text":"Conjunto total de individuos, elementos, eventos o datos que comparten una o más características comunes.","images":["data:image/png;base64,"]},{"letter":"D","text":"Utiliza relatos subjetivos.","images":["data:image/png;base64,"]}],"answer":"C","multi":false,"explanation":"En investigación, la población es el conjunto total de individuos, elementos, eventos o datos que comparten características comunes.","explanationImages":[]},{"id":"TIC-04","num":4,"text":"Identificar cuál de las siguientes afirmaciones corresponde a las conclusiones.","questionImages":[],"options":[{"letter":"A","text":"Permite crear nuevos experimentos.","images":["data:image/png;base64,"]},{"letter":"B","text":"Copia de estudios anteriores.","images":["data:image/png;base64,"]},{"letter":"C","text":"Refuerzan los objetivos específicos y son datos propios.","images":["data:image/png;base64,"]}],"answer":"C","multi":false,"explanation":"Las conclusiones deben relacionarse con los objetivos específicos y apoyarse en los resultados propios del trabajo.","explanationImages":[]},{"id":"TIC-05","num":5,"text":"Enumerar lo que se especifica en el cronograma.","questionImages":[],"options":[{"letter":"A","text":"Un grupo de comparación.","images":["data:image/png;base64,"]},{"letter":"B","text":"Las observaciones.","images":["data:image/png;base64,"]},{"letter":"C","text":"La organización, el orden y el tiempo.","images":["data:image/png;base64,"]},{"letter":"D","text":"Solo lo que se hace en laboratorios profesionales.","images":["data:image/png;base64,"]}],"answer":"C","multi":false,"explanation":"El cronograma organiza las actividades, su orden y el tiempo previsto para desarrollarlas.","explanationImages":[]},{"id":"TIC-06","num":6,"text":"¿Qué parte del informe de investigación presenta los resultados obtenidos?","questionImages":[],"options":[{"letter":"A","text":"Introducción.","images":["data:image/png;base64,"]},{"letter":"B","text":"Metodología.","images":["data:image/png;base64,"]},{"letter":"C","text":"Resultados.","images":["data:image/png;base64,"]},{"letter":"D","text":"Justificación.","images":["data:image/png;base64,"]}],"answer":"C","multi":false,"explanation":"La sección de resultados presenta los datos y hallazgos obtenidos durante la investigación.","explanationImages":[]},{"id":"TIC-07","num":7,"text":"Identificar qué define el glosario.","questionImages":[],"options":[{"letter":"A","text":"Cualitativa nominal.","images":["data:image/png;base64,"]},{"letter":"B","text":"Cualitativa ordinal.","images":["data:image/png;base64,"]},{"letter":"C","text":"Cuantitativa discreta.","images":["data:image/png;base64,"]},{"letter":"D","text":"Lista de términos o palabras especializadas.","images":["data:image/png;base64,"]}],"answer":"D","multi":false,"explanation":"El glosario es una lista de términos o palabras especializadas utilizadas en el trabajo.","explanationImages":[]},{"id":"TIC-08","num":8,"text":"Identificar tres recursos que deben estar en el trabajo de investigación.","questionImages":[],"options":[{"letter":"A","text":"Bibliográficos.","images":["data:image/png;base64,"]},{"letter":"B","text":"Materiales físicos y digitales.","images":["data:image/png;base64,"]},{"letter":"C","text":"Humanos.","images":["data:image/png;base64,"]},{"letter":"D","text":"Todos los anteriores.","images":["data:image/png;base64,"]}],"answer":"D","multi":false,"explanation":"Un trabajo de investigación puede requerir recursos bibliográficos, materiales físicos y digitales, y recursos humanos.","explanationImages":[]},{"id":"TIC-09","num":9,"text":"Identificar cuál de los siguientes verbos se podría usar para escribir una conclusión.","questionImages":[],"options":[{"letter":"A","text":"Analizando.","images":["data:image/png;base64,"]},{"letter":"B","text":"Escribiendo.","images":["data:image/png;base64,"]},{"letter":"C","text":"Diseñando.","images":["data:image/png;base64,"]},{"letter":"D","text":"Estudiar.","images":["data:image/png;base64,"]}],"answer":"A","multi":false,"explanation":"La opción resaltada en el cuestionario es “analizando”, por eso es la respuesta correcta.","explanationImages":[]}]},{"title":"Comunicaciones Moviles","script":"repaso_comunicaciones_moviles.py","questions":[{"id":"MOV-01","num":1,"text":"¿Cuál es una ventaja clave del acceso múltiple por división en código (CDMA) en comparación con FDMA y TDMA?","questionImages":[],"options":[{"letter":"A","text":"Mayor necesidad de sincronización","images":[]},{"letter":"B","text":"Mayor sensibilidad al efecto de multicamino","images":[]},{"letter":"C","text":"Alta eficiencia espectral y tolerancia a desvanecimientos","images":[]},{"letter":"D","text":"Uso exclusivo en sistemas satelitales","images":[]}],"answer":"C","multi":false,"explanation":"CDMA: alta eficiencia espectral y tolerancia a desvanecimientos.","explanationImages":[]},{"id":"MOV-02","num":2,"text":"¿Cuál es la función principal del componente SGSN dentro de la arquitectura GPRS?","questionImages":[],"options":[{"letter":"A","text":"Gestionar los recursos del canal de voz","images":[]},{"letter":"B","text":"Facilitar la conexión entre redes fijas e IP","images":[]},{"letter":"C","text":"Controlar la transmisión de paquetes por la red de acceso","images":[]},{"letter":"D","text":"Gestionar la movilidad y transmisión de datos de usuarios GPRS","images":[]}],"answer":"D","multi":false,"explanation":"SGSN gestiona movilidad y datos en GPRS.","explanationImages":[]},{"id":"MOV-03","num":3,"text":"¿Cuál es la principal mejora técnica de EDGE sobre GPRS para incrementar la tasa de transmisión?","questionImages":[],"options":[{"letter":"A","text":"Uso de ranuras adicionales en TDMA","images":[]},{"letter":"B","text":"Migración a redes todo IP","images":[]},{"letter":"C","text":"Implementación de modulación 8PSK","images":[]},{"letter":"D","text":"Reducción de la señal de sincronización","images":[]}],"answer":"C","multi":false,"explanation":"EDGE aumenta tasa usando modulación 8PSK.","explanationImages":[]},{"id":"MOV-04","num":4,"text":"En el sistema UMTS, ¿qué característica fundamental permite el soporte de servicios multimedios y mayor capacidad?","questionImages":[],"options":[{"letter":"A","text":"Acceso por división en frecuencia","images":[]},{"letter":"B","text":"Arquitectura basada en conmutación de circuitos","images":[]},{"letter":"C","text":"Uso de CDMA de banda ancha (W-CDMA)","images":[]},{"letter":"D","text":"Separación física de las capas OS","images":[]}],"answer":"C","multi":false,"explanation":"UMTS usa W-CDMA.","explanationImages":[]},{"id":"MOV-05","num":5,"text":"¿Cuál es la finalidad del Inter-Cell Interference Coordination (ICIC) en redes LTE?","questionImages":[],"options":[{"letter":"A","text":"Mejorar la capacidad en zonas rurales","images":[]},{"letter":"B","text":"Reducir la interferencia en el borde de celda","images":[]},{"letter":"C","text":"Optimizar el direccionamiento IP","images":[]},{"letter":"D","text":"Aumentar el número de slots disponibles","images":[]}],"answer":"B","multi":false,"explanation":"ICIC reduce interferencia en el borde de celda.","explanationImages":[]},{"id":"MOV-06","num":6,"text":"¿Cuál es una ventaja del modelo de Walfisch-Bertoni respecto al modelo de Okumura-Hata en entornos urbanos densos?","questionImages":[],"options":[{"letter":"A","text":"Bajo coste computacional","images":[]},{"letter":"B","text":"Considera la difracción por edificios","images":[]},{"letter":"C","text":"Precisión en zonas suburbanas","images":[]},{"letter":"D","text":"Incluye pérdidas por ionosfera","images":[]}],"answer":"B","multi":false,"explanation":"Walfisch-Bertoni modela difracción por edificios en urbano denso.","explanationImages":[]},{"id":"MOV-07","num":7,"text":"¿Qué variable es determinante para definir el ancho de banda de coherencia en un canal móvil?","questionImages":[],"options":[{"letter":"A","text":"Frecuencia central de transmisión","images":[]},{"letter":"B","text":"Variación de fase en el tiempo","images":[]},{"letter":"C","text":"Tipo de codificación de canal","images":[]},{"letter":"D","text":"Dispersión temporal (delay spread)","images":[]}],"answer":"D","multi":false,"explanation":"El coherence bandwidth depende del delay spread.","explanationImages":[]},{"id":"MOV-08","num":8,"text":"En un cálculo de presupuesto de enlace LTE, ¿qué componente representa las pérdidas máximas permitidas del canal entre UE y eNodeB?","questionImages":[],"options":[{"letter":"A","text":"Throughput teórico","images":[]},{"letter":"B","text":"Shannon Capacity","images":[]},{"letter":"C","text":"MAPL (Maximum Allowable Path Loss)","images":[]},{"letter":"D","text":"Inter Site Distance (ISD)","images":[]}],"answer":"C","multi":false,"explanation":"MAPL: máxima pérdida de trayecto permitida.","explanationImages":[]},{"id":"MOV-09","num":9,"text":"¿Cuál de las siguientes características define a 5G NR en su capa física?","questionImages":[],"options":[{"letter":"A","text":"OFDM flexible con múltiples númerologías","images":[]},{"letter":"B","text":"Subportadoras de ancho fijo de 15 kHz","images":[]},{"letter":"C","text":"Uso exclusivo de FDD","images":[]},{"letter":"D","text":"Solo es compatible con bandas por debajo de 6 GHz","images":[]}],"answer":"A","multi":false,"explanation":"5G NR: OFDM flexible con múltiples númerologías.","explanationImages":[]},{"id":"MOV-10","num":10,"text":"¿Cuál de los siguientes modelos está orientado específicamente para caracterizar canales en bandas milimétricas en escenarios urbanos microcelulares?","questionImages":[],"options":[{"letter":"A","text":"COST 231-Hata","images":[]},{"letter":"B","text":"Sakagami Extendido","images":[]},{"letter":"C","text":"NYUSIM UMi","images":[]},{"letter":"D","text":"Ericsson 9999","images":[]}],"answer":"C","multi":false,"explanation":"NYUSIM UMi: mmWave urbano microcelular.","explanationImages":[]}]},{"title":"Comunicaciones Opticas","script":"repaso_comunicaciones_opticas.py","questions":[{"id":"OPT-01","num":1,"text":"¿Cuál es la función principal de una fibra óptica monomodo?","questionImages":[],"options":[{"letter":"A","text":"Transmitir múltiples modos de luz simultáneamente","images":[]},{"letter":"B","text":"Aumentar la dispersión modal","images":[]},{"letter":"C","text":"Reducir la atenuación y permitir transmisiones a larga distancia","images":[]},{"letter":"D","text":"Reflejar las señales ópticas para análisis espectral","images":[]}],"answer":"C","multi":false,"explanation":"Monomodo: reduce dispersión modal y permite largas distancias.","explanationImages":[]},{"id":"OPT-02","num":2,"text":"¿Qué componente convierte señales eléctricas en señales ópticas en un sistema de comunicaciones ópticas?","questionImages":[],"options":[{"letter":"A","text":"Receptor óptico","images":[]},{"letter":"B","text":"Amplificador óptico.","images":[]},{"letter":"C","text":"Fuente láser o LED","images":[]},{"letter":"D","text":"Divisor óptico","images":[]}],"answer":"C","multi":false,"explanation":"Láser/LED convierte señales eléctricas a ópticas.","explanationImages":[]},{"id":"OPT-03","num":3,"text":"¿Qué característica mejora la eficiencia de transmisión en fibras ópticas?","questionImages":[],"options":[{"letter":"A","text":"Mayor índice de refracción del núcleo","images":[]},{"letter":"B","text":"Menor índice de absorción del recubrimiento","images":[]},{"letter":"C","text":"Alta pureza del vidrio y precisión en el núcleo","images":[]},{"letter":"D","text":"Uso de conectores metálicos","images":[]}],"answer":"C","multi":false,"explanation":"Alta pureza y precisión del núcleo reduce pérdidas.","explanationImages":[]},{"id":"OPT-04","num":4,"text":"¿Qué propiedad del núcleo de una fibra óptica permite la propagación de la luz por reflexión interna total?","questionImages":[],"options":[{"letter":"A","text":"Su baja absorción térmica","images":[]},{"letter":"B","text":"Su índice de refracción más alto que el del revestimiento","images":[]},{"letter":"C","text":"Su geometría cilíndrica","images":[]},{"letter":"D","text":"Su resistencia mecánica","images":[]}],"answer":"B","multi":false,"explanation":"Reflexión interna total requiere n_núcleo > n_revestimiento.","explanationImages":[]},{"id":"OPT-05","num":5,"text":"¿Cuál es el propósito de utilizar amplificadores ópticos en enlaces de larga distancia?","questionImages":[],"options":[{"letter":"A","text":"Reducir la dispersión cromática","images":[]},{"letter":"B","text":"Disminuir la interferencia electromagnética","images":[]},{"letter":"C","text":"Reforzar la señal sin necesidad de conversión eléctrica","images":[]},{"letter":"D","text":"Multiplexar señales ópticas","images":[]}],"answer":"C","multi":false,"explanation":"Amplificación óptica sin conversión eléctrica.","explanationImages":[]},{"id":"OPT-06","num":6,"text":"¿Qué fenómeno limita la velocidad de transmisión en fibras multimodo?","questionImages":[],"options":[{"letter":"A","text":"Dispersión por polarización","images":[]},{"letter":"B","text":"Dispersión modal","images":[]},{"letter":"C","text":"Dispersión cromática","images":[]},{"letter":"D","text":"Atenuación por absorción","images":[]}],"answer":"B","multi":false,"explanation":"Multimodo limitado por dispersión modal.","explanationImages":[]},{"id":"OPT-07","num":7,"text":"¿Qué parámetro caracteriza la eficiencia con la que una fibra óptica transporta energía óptica?","questionImages":[],"options":[{"letter":"A","text":"Índice de atenuación","images":[]},{"letter":"B","text":"Índice de refracción","images":[]},{"letter":"C","text":"Longitud de onda","images":[]},{"letter":"D","text":"Ángulo de aceptación","images":[]}],"answer":"A","multi":false,"explanation":"La eficiencia de transporte en una fibra se caracteriza por su atenuación (pérdida en dB/km). La NA/ángulo de aceptación describe acoplamiento de entrada, no la pérdida durante el trayecto.","explanationImages":[]},{"id":"OPT-08","num":8,"text":"¿Qué elemento se utiliza para dividir o combinar señales ópticas en una red de distribución óptica pasiva (PON)?","questionImages":[],"options":[{"letter":"A","text":"Filtro óptico","images":[]},{"letter":"B","text":"Láser de bombeo","images":[]},{"letter":"C","text":"Divisor óptico (splitter)","images":[]},{"letter":"D","text":"Modulador óptico","images":[]}],"answer":"C","multi":false,"explanation":"Splitter divide/combina señales en PON.","explanationImages":[]},{"id":"OPT-09","num":9,"text":"¿Qué técnica permite aumentar la capacidad de transmisión de una sola fibra óptica usando diferentes colores de luz?","questionImages":[],"options":[{"letter":"A","text":"Modulación por amplitud","images":[]},{"letter":"B","text":"Multiplexación por división de longitud de onda (WDM)","images":[]},{"letter":"C","text":"Modulación por frecuencia","images":[]},{"letter":"D","text":"Amplificación óptica","images":[]}],"answer":"B","multi":false,"explanation":"WDM usa diferentes longitudes de onda (colores).","explanationImages":[]},{"id":"OPT-10","num":10,"text":"¿Qué función cumple un receptor óptico en un sistema de comunicaciones ópticas?","questionImages":[],"options":[{"letter":"A","text":"Convertir la señal óptica en una señal eléctrica","images":[]},{"letter":"B","text":"Multiplexar varias señales ópticas","images":[]},{"letter":"C","text":"Amplificar la señal óptica entrante","images":[]},{"letter":"D","text":"Filtrar señales de interferencia","images":[]}],"answer":"A","multi":false,"explanation":"Receptor óptico convierte señal óptica en eléctrica.","explanationImages":[]}]}]);
